    exercises: [
      { type: 'MCQ_Trans', question: 'O que significa?', audio: "Hier, j'ai travaillé toute la journée.", choices: ['Ontem, eu vou trabalhar o dia todo.', 'Ontem, eu trabalhei o dia todo.', 'Amanhã, eu trabalho o dia todo.', 'Ontem, eu estava trabalhando.'], answer: 'Ontem, eu trabalhei o dia todo.', explanation: 'Passé composé = ação concluída no passado. J\'ai travaillé = eu trabalhei. Hier = ontem.' },
      { type: 'MCQ', question: 'MANGER — passé composé de "nous"', choices: ['nous avons mangé', 'nous sommes mangé', 'nous avons manger', 'nous avons mangés'], answer: 'nous avons mangé', explanation: 'Manger usa AVOIR. Nous avons + participe (mangé). Com avoir, participe nunca concorda com sujeito.' },
      { type: 'MCQ', question: 'ALLER — passé composé de "elle"', choices: ['elle a allé', 'elle est allée', 'elle est allé', 'elle a été allée'], answer: 'elle est allée', explanation: 'Aller usa ÊTRE. Elle (fem. sing.) → allée (+e). Com être, participe concorda: elle est allÉE.' },
      { type: 'MCQ_Trans', question: 'O que significa?', audio: 'Nous avons vu un film super hier soir.', choices: ['Nós vamos ver um filme ótimo hoje à noite.', 'Nós vimos um filme ótimo ontem à noite.', 'Nós estávamos assistindo um filme ótimo.', 'Nós queremos ver um filme ótimo.'], answer: 'Nós vimos um filme ótimo ontem à noite.', explanation: 'Voir → participe: vu (irregular). Nous avons vu = nós vimos. Avoir = auxiliar.' },
      { type: 'WordOrder', question: 'Monte a frase:', translation: 'Ela tomou o café da manhã e foi embora.', words: ['Elle', 'a', 'pris', 'son', 'petit-déjeuner', 'et', 'elle', 'est', 'partie'], answer: 'Elle a pris son petit-déjeuner et elle est partie.', audio: 'Elle a pris son petit-déjeuner et elle est partie.', explanation: 'Prendre (avoir) → pris. Partir (être) → partie.' },
      { type: 'MCQ', question: '"Les filles ont chanté" — por que participe não tem -es?', choices: ['É irregular', 'Com avoir, participe nunca concorda com o sujeito', 'É um erro aceito', 'Filles é considerado masculino'], answer: 'Com avoir, participe nunca concorda com o sujeito', explanation: 'REGRA DE OURO: com AVOIR → participe CONGELADO (nunca muda). Com ÊTRE → concorda. Les filles ont chantÉ.' },
      { type: 'MCQ', question: 'VENIR — passé composé de "ils"', choices: ['ils ont venu', 'ils sont venus', 'ils sont venu', 'ils ont venus'], answer: 'ils sont venus', explanation: 'Venir usa ÊTRE. Ils (masc. plural) → venus (+s). Ils sont venuS.' },
      { type: 'MCQ_Trans', question: 'O que significa?', audio: 'Je me suis levé très tôt ce matin.', choices: ['Eu vou me levantar cedo amanhã.', 'Eu me levantei muito cedo esta manhã.', 'Eu precisei me levantar cedo hoje.', 'Eu costumava me levantar cedo.'], answer: 'Eu me levantei muito cedo esta manhã.', explanation: 'Verbo reflexivo: se lever → passé composé com ÊTRE. Je me suis levé(e) = eu me levantei.' },
      { type: 'WordOrder', question: 'Monte a frase:', translation: 'Elas se encontraram no café depois da aula.', words: ['Elles', 'se', 'sont', 'retrouvées', 'au', 'café', 'après', 'le', 'cours'], answer: 'Elles se sont retrouvées au café après le cours.', audio: 'Elles se sont retrouvées au café après le cours.', explanation: 'Se retrouver (reflexivo, être) → retrouvées (fem. plural).' },
      { type: 'MCQ', question: 'Participe de FAIRE:', choices: ['faisé', 'fait', 'fais', 'faité'], answer: 'fait', explanation: 'Faire → fait (irregular). J\'ai fait = eu fiz. Outros irregulares: être→été, avoir→eu, prendre→pris, voir→vu.' },
      { type: 'MCQ', question: 'DESCENDRE — "Ils ___ du train à Lyon."', choices: ['sont descendus', 'ont descendu', 'sont descendu', 'ont descendus'], answer: 'sont descendus', explanation: 'Descendre usa ÊTRE (está nos 14 verbos!). Ils (masc. plural) → descendus (+s). Ils sont descenduS.' },
      { type: 'MCQ_Trans', question: 'O que significa?', audio: "Dès qu'il a fini de manger, il a commencé à travailler.", choices: ['Quando ele terminou de comer, ele começou a trabalhar.', 'Antes de comer, ele já havia trabalhado.', 'Ele comeu e depois foi trabalhar mais tarde.', 'Assim que ele terminou de comer, ele começou a trabalhar.'], answer: 'Assim que ele terminou de comer, ele começou a trabalhar.', explanation: '"Dès que" = assim que (imediatamente após). Mais preciso que "quand". Dois passés composés = duas ações consecutivas.' },
      { type: 'WordOrder', question: 'Monte a frase:', translation: 'Nós decidimos mudar de emprego depois da reunião.', words: ['Nous', 'avons', 'décidé', 'de', 'changer', 'de', 'travail', 'après', 'la', 'réunion'], answer: 'Nous avons décidé de changer de travail après la réunion.', audio: 'Nous avons décidé de changer de travail après la réunion.', explanation: 'Décider de + infinitif. Changer de travail = mudar de emprego.' },
      { type: 'MCQ', question: '"La lettre que j\'ai ___" — participe de ÉCRIRE:', choices: ['écris', 'écrite', 'écrit', 'écrits'], answer: 'écrite', explanation: 'COD avant auxiliaire avoir → participe concorda! "La lettre" (fém. sg.) é COD antes de "ai" → écriTE. Regra avançada!' },
      { type: 'MCQ', question: 'Qual está CORRETO?', choices: ["Ils se sont lavés les mains.", "Ils se sont lavé les mains.", "Ils ont lavé les mains.", "Ils ont se lavé les mains."], answer: "Ils se sont lavé les mains.", explanation: '"Se laver les mains": "les mains" é COD que vem depois → participe NÃO concorda. Ils se sont lavÉ les mains.' },
      { type: 'MCQ_Trans', question: 'O que significa?', audio: 'Combien de fois es-tu allé en France ?', choices: ['Quando você vai para a França?', 'Quantas vezes você foi à França?', 'Quanto custa ir à França?', 'Há quanto tempo você vai à França?'], answer: 'Quantas vezes você foi à França?', explanation: '"Combien de fois" = quantas vezes. Aller usa ÊTRE. Tu → es allé(e). Pergunta com inversão formal.' },
      { type: 'WordOrder', question: 'Monte a frase:', translation: 'Eu ainda não recebi a resposta dele.', words: ["Je", "n'ai", "pas", "encore", "reçu", "sa", "réponse"], answer: "Je n'ai pas encore reçu sa réponse.", audio: "Je n'ai pas encore reçu sa réponse.", explanation: 'Ne...pas encore = ainda não. Recevoir → reçu (irregular).' },
      { type: 'MCQ', question: 'NAÎTRE — passé composé de "il"', choices: ['il a né', 'il est né', 'il est naît', 'il a naît'], answer: 'il est né', explanation: 'Naître usa ÊTRE (está nos 14 verbos). Participe: né. Il est né = ele nasceu. Ex: Il est né en 1990 à Paris.' },
      { type: 'MCQ', question: 'Por que "Elles se sont téléphon_" não tem -ées?', choices: ['Téléphoner é irregular', 'Se téléphoner: o pronome é COI, não COD → sem acordo', 'Elles é masculino aqui', 'Erro de concordância aceito'], answer: 'Se téléphoner: o pronome é COI, não COD → sem acordo', explanation: '"Se téléphoner" = ligar uma para a outra. "Se" = COI (indireto). Com COI, participe não concorda → téléphonÉ. Regra refinada!' },
      { type: 'MCQ_Trans', question: 'O que significa?', audio: 'Ils sont restés à la maison tout le week-end.', choices: ['Eles vão ficar em casa todo o fim de semana.', 'Eles ficaram em casa o fim de semana todo.', 'Eles estavam em casa durante o fim de semana.', 'Eles precisaram ficar em casa no fim de semana.'], answer: 'Eles ficaram em casa o fim de semana todo.', explanation: 'Rester usa ÊTRE (está nos 14 verbos!). Ils (masc. plural) → restés (+s). Ils sont restéS.' },
    ]
